import{_ as a,a as t,b as d,c as r}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as o,o as l,c,a2 as i}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Añadir un canal compatible con S3","description":"","frontmatter":{},"headers":[],"relativePath":"es/upload/s3.md","filePath":"es/upload/s3.md","lastUpdated":1781962217000}'),s={name:"es/upload/s3.md"};function n(p,e,u,h,b,m){return l(),c("div",null,[...e[0]||(e[0]=[i(`<h1 id="anadir-un-canal-compatible-con-s3" tabindex="-1">Añadir un canal compatible con S3 <a class="header-anchor" href="#anadir-un-canal-compatible-con-s3" aria-label="Permalink to &quot;Añadir un canal compatible con S3&quot;">​</a></h1><p>El canal S3 permite usar almacenamiento de objetos compatible con la API S3.</p><p>Sirve para Cloudflare R2, Backblaze B2, MinIO, AWS S3 y otros servicios compatibles.</p><h2 id="que-preparar" tabindex="-1">Qué preparar <a class="header-anchor" href="#que-preparar" aria-label="Permalink to &quot;Qué preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Uso</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>URL de API del almacenamiento</td></tr><tr><td>Bucket</td><td>Bucket donde se guardarán los archivos</td></tr><tr><td>Region</td><td>Región del almacenamiento; en Cloudflare R2 suele ser <code>auto</code></td></tr><tr><td>Access Key ID</td><td>Clave de acceso</td></tr><tr><td>Secret Access Key</td><td>Clave secreta</td></tr><tr><td>Dominio CDN</td><td>Opcional, para URLs públicas personalizadas</td></tr></tbody></table><p>Ejemplo con Cloudflare R2 por API S3:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://tuAccountID.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: nombre-del-bucket</span></span>
<span class="line"><span>Region: auto</span></span></code></pre></div><h2 id="donde-se-anade" tabindex="-1">Dónde se añade <a class="header-anchor" href="#donde-se-anade" aria-label="Permalink to &quot;Dónde se añade&quot;">​</a></h2><ol><li>Abre Configuración del sistema.</li><li>Entra en Configuración de subida.</li><li>Haz clic en <code>Añadir canal</code>.</li><li>Selecciona <code>S3</code>.</li></ol><h2 id="campos" tabindex="-1">Campos <a class="header-anchor" href="#campos" aria-label="Permalink to &quot;Campos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Descripción</th></tr></thead><tbody><tr><td>Nombre del canal</td><td>Por ejemplo <code>R2-S3</code> o <code>MinIO</code></td></tr><tr><td>Endpoint</td><td>URL S3 completa con <code>https://</code></td></tr><tr><td>Dominio CDN personalizado</td><td>Opcional; se usa al generar enlaces</td></tr><tr><td>Bucket</td><td>Nombre del bucket</td></tr><tr><td>Region</td><td><code>auto</code> para R2; otros proveedores según documentación</td></tr><tr><td>Access Key ID</td><td>Clave de acceso</td></tr><tr><td>Secret Access Key</td><td>Clave secreta</td></tr><tr><td>Path-style access</td><td>Solo si el proveedor lo requiere</td></tr><tr><td>Límite de capacidad</td><td>Opcional</td></tr></tbody></table><h2 id="crear-claves-s3-para-r2" tabindex="-1">Crear claves S3 para R2 <a class="header-anchor" href="#crear-claves-s3-para-r2" aria-label="Permalink to &quot;Crear claves S3 para R2&quot;">​</a></h2><p>En Cloudflare Dashboard, abre <code>R2 Object Storage</code> y entra a la gestión de API Tokens.</p><p>![Entrada R2 API Token](../../image/upload/s3/r2 api token入口.png)</p><p>Crea un token R2 con acceso al bucket objetivo.</p><p><img src="`+a+'" alt="Crear API Token" loading="lazy"></p><p>Copia <code>Access Key ID</code> y <code>Secret Access Key</code>.</p><p><img src="'+t+'" alt="Copiar valores" loading="lazy"></p><h2 id="rellenar-en-imgbed" tabindex="-1">Rellenar en ImgBed <a class="header-anchor" href="#rellenar-en-imgbed" aria-label="Permalink to &quot;Rellenar en ImgBed&quot;">​</a></h2><ol><li>Introduce <code>Endpoint</code>, <code>Bucket</code> y <code>Region</code>.</li><li>Introduce Access Key ID y Secret Access Key.</li><li>Si usas CDN, rellena el dominio personalizado.</li><li>Activa Path-style access solo si el servicio lo exige.</li><li>Guarda.</li></ol><p><img src="'+d+'" alt="Configuración S3" loading="lazy"></p><h2 id="verificacion" tabindex="-1">Verificación <a class="header-anchor" href="#verificacion" aria-label="Permalink to &quot;Verificación&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Punto</th><th>Estado esperado</th></tr></thead><tbody><tr><td>Tarjeta del canal</td><td>Aparece después de guardar</td></tr><tr><td>Subida de prueba</td><td>Se crea un objeto en el bucket</td></tr><tr><td>Enlace</td><td>La URL devuelta por ImgBed abre bien</td></tr><tr><td>Capacidad</td><td>Si hay límite, se muestra el uso</td></tr></tbody></table><p><img src="'+r+'" alt="Capacidad S3" loading="lazy"></p><p>La estadística de capacidad S3 se calcula desde los registros locales de ImgBed en D1, no escaneando el bucket en tiempo real.</p><h2 id="errores-habituales" tabindex="-1">Errores habituales <a class="header-anchor" href="#errores-habituales" aria-label="Permalink to &quot;Errores habituales&quot;">​</a></h2><ul><li>Endpoint sin <code>https://</code>.</li><li>Bucket o Region incorrectos.</li><li>Access Key sin permiso de escritura.</li><li>El proveedor requiere Path-style access.</li><li>CDN no conectado correctamente al bucket.</li></ul>',27)])])}const y=o(s,[["render",n]]);export{k as __pageData,y as default};
